// You can use this step to execute a variety of server-side javascript tests including
// jasmine tests and custom assertions
//
//
// Pass or fail a step: Override the step outcome to pass or fail. This is ignored
//                      by jasmine tests
//
//  - Return true from the main function body to pass the step
//  - Return false from the main function body to fail the step
//
//
// outputs:       Pre-defined Step config Output variables to set on this step during
//                execution that are available to later steps
//
// steps(SYS_ID): A function to retrieve Output variable data from a step that executed
//                earlier in the test. The desired step's sys_id is required
//
//  Example:
//
//      // Test step 1 - add data
//      var gr = new GlideRecord('sc_task');
//      // this sample step's Step config has Output variables named table and record_id
//      outputs.table = 'sc_task';
//      outputs.record_id = gr.insert();
//
//      // Test step 2 - access added data and validate
//      // check that the record exists (or that business logic changed it)
//      var gr = new GlideRecord("sc_task");
//      gr.get(steps(PREVIOUS_STEP_SYS_ID).record_id);
//      assertEqual({name: "task gr exists", shouldbe: true, value: gr.isValidRecord()});
//
//
// stepResult.setOutputMessage: Log a message to step results after step executes.
//                              Can only be called once or will overwrite previous
//                              message
//
//  Example:
//
//      var gr = new GlideRecord('sc_task');
//      gr.setValue('short_description', 'verify task can be inserted');
//      var grSysId = gr.insert();
//      var justCreatedGR = new GlideRecord('sc_task');
//      if (justCreatedGR.get(grSysId)) {
//            stepResult.setOutputMessage("Successfully inserted task record");
//            return true; // pass the step
//      } else {
//            stepResult.setOutputMessage("Failed to insert task record");
//            return false; // fail the step
//      }
//
//
// Note: describe is only supported in Global scope.
// Use 'describe' to create a suite of test scripts and 'it' to define test expectations
//
//  Example jasmine test:
//
//      describe('my suite of script tests', function() {
//            it('should meet expectations', function() {
//                  expect(true).not.toBe(false);
//            });
//      });
//      // make sure to uncomment jasmine.getEnv().execute(); outside the function body
//
//
// assertEqual: A function used to compare that assertion.shouldbe == assertion.value;
//              in case of failure it throws an Error and logs that the assertion by
//              name has failed
//
//  Example:
//
//      var testAssertion = {
//            name: "my test assertion",
//            shouldbe: "expected value"
//            value: "actual value",
//      };
//      assertEqual(testAssertion); // throws Error, logs message to test step output
//
(function (outputs, steps, stepResult, assertEqual) {
	
	var testCore;
	var outputMsg = '';
	var passwordSuccessful = false;
	var tokenSuccessful = false;
	var usernamePropName = 'x_taniu_tan_core.tanium_username';
	var passwordPropName = 'x_taniu_tan_core.tanium_password';
	var apiTokenPropName = 'x_taniu_tan_core.tanium_api_token';
	var usernameIsSet = !!gs.getProperty(usernamePropName, '');
	var passwordIsSet = !!gs.getProperty(passwordPropName, '');
	var tokenIsSet = !!gs.getProperty(apiTokenPropName, '');
	
	//If both API token alone, and both username and password properties ar enot set, bail.
	if ((!usernameIsSet || !passwordIsSet) && !tokenIsSet) {
		outputMsg += 'Either API token, or username/password system properties must be set for authentication to work. Cannot continue.';
		stepResult.setOutputMessage(outputMsg);
		return false;
	}
	
	try {
		//Test username/password auth, if properties are set.
		if (usernameIsSet && passwordIsSet) {
			testCore = new x_taniu_tan_core.TaniumIntegrationCore();
			passwordSuccessful = !!testCore.__getSessionID();
			if (passwordSuccessful) {
				outputMsg += 'Successfully logged in using username and password pair.\n';
			}
		}
		
		//Test token auth, if property is set.
		if (tokenIsSet) {
			testCore = new x_taniu_tan_core.TaniumIntegrationCore(true);
			tokenSuccessful = !!testCore.__getSessionID();
		}
	} catch(ex) {
		outputMsg += 'Something went wrong while testing authentication. This likely means ' +
			'that either the Tanium instance URL is not properly set, or that the username/' +
			'password or API token provided are not properly set. Re-running the Guided ' +
			'Setup may resolve this issue.\n' +
			'ERROR: ' + ex.message.toString() + '\n';
		stepResult.setOutputMessage(outputMsg);
		return false;
	}
	
	//If authentication successful, add message and return true.
	if (passwordSuccessful || tokenSuccessful) {
		//Could've done this via ternary, but why be pretentious about it?
		if (passwordSuccessful) {
			outputMsg += 'Authentication via password successful.\n';
		} else {
			outputMsg += 'Could not authenticate with username/password.\n';
		}
		
		if (tokenSuccessful) {
			outputMsg += 'Authentication via API token successful.\n';
		} else {
			outputMsg += 'Could not authenticate with API token.\n';
		}
		
		stepResult.setOutputMessage(outputMsg);
		return true;
	}
	
	//If we did not return above, then authentication failed. Outputting error and returning false.
	outputMsg += 'API token and username/password system properties have not been set. You can ' +
		'set these properties by following the guided setup steps from Tanium Integration Core > ' +
		'Guided Setup in the Application Navigator bar of your ServiceNow instance.\n';
	
	stepResult.setOutputMessage(outputMsg);
	return false;
	
})(outputs, steps, stepResult, assertEqual);
// uncomment the next line to execute this script as a jasmine test
//jasmine.getEnv().execute();
